import{_ as e,o,c as r,a3 as a}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"Editor Overview","description":"Learn the edit modes, status bar, breadcrumbs, and copy/export actions in the Notely editor.","frontmatter":{"title":"Editor Overview","description":"Learn the edit modes, status bar, breadcrumbs, and copy/export actions in the Notely editor.","keywords":"editor, edit mode, split view, preview, status bar, breadcrumbs, word count","category":"Editor"},"headers":[],"relativePath":"editor/index.md","filePath":"editor/index.md","lastUpdated":1784869909000}'),i={name:"editor/index.md"};function d(n,t,s,l,c,h){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="editor-overview" tabindex="-1">Editor Overview <a class="header-anchor" href="#editor-overview" aria-label="Permalink to &quot;Editor Overview&quot;">​</a></h1><p>The Notely editor is the primary workspace for writing and reviewing Markdown notes. It supports four view modes, a rich toolbar, real-time validation, and statistics.</p><h2 id="view-modes" tabindex="-1">View Modes <a class="header-anchor" href="#view-modes" aria-label="Permalink to &quot;View Modes&quot;">​</a></h2><p>Switch modes using the mode buttons in the editor header bar.</p><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th></tr></thead><tbody><tr><td><strong>Edit</strong></td><td>Raw Markdown source editor with syntax highlighting and completions</td></tr><tr><td><strong>Split</strong></td><td>Editor on the left, live rendered preview on the right</td></tr><tr><td><strong>Preview</strong></td><td>Full-width read-only rendered output</td></tr><tr><td><strong>Web</strong></td><td>Website-style rendering — higher-fidelity preview with full media support</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Split Mode for Writing</p><p>Split mode is the most productive mode for writing. You can edit Markdown on the left while watching the formatted output update in real time on the right.</p></div><h2 id="status-bar" tabindex="-1">Status Bar <a class="header-anchor" href="#status-bar" aria-label="Permalink to &quot;Status Bar&quot;">​</a></h2><p>The status bar at the bottom of the editor shows live document statistics:</p><table tabindex="0"><thead><tr><th>Stat</th><th>Description</th></tr></thead><tbody><tr><td><strong>Word count</strong></td><td>Live count of words in the current content</td></tr><tr><td><strong>Line count</strong></td><td>Total lines in the document</td></tr><tr><td><strong>Reading time</strong></td><td>Estimated reading time (calculated at 200 wpm)</td></tr></tbody></table><p>Statistics update independently when switching between Edit and other modes.</p><h2 id="breadcrumbs" tabindex="-1">Breadcrumbs <a class="header-anchor" href="#breadcrumbs" aria-label="Permalink to &quot;Breadcrumbs&quot;">​</a></h2><p>The breadcrumb trail in the editor header shows the full folder path to the current note.</p><ul><li>Click any breadcrumb segment to navigate to that folder.</li><li>Updates automatically when you switch notes.</li><li>Useful when working in deeply nested folder structures.</li></ul><h2 id="copy-and-export-actions" tabindex="-1">Copy and Export Actions <a class="header-anchor" href="#copy-and-export-actions" aria-label="Permalink to &quot;Copy and Export Actions&quot;">​</a></h2><p>From the editor toolbar you can export note content without leaving the app:</p><table tabindex="0"><thead><tr><th>Action</th><th>Output</th></tr></thead><tbody><tr><td><strong>Copy as HTML</strong></td><td>Formatted HTML — paste into email clients, Notion, or CMS systems</td></tr><tr><td><strong>Copy as Plain Text</strong></td><td>Plain text without Markdown syntax</td></tr></tbody></table><p>Both actions show a success notification and copy to the clipboard.</p><h3 id="copy-link-path" tabindex="-1">Copy Link Path <a class="header-anchor" href="#copy-link-path" aria-label="Permalink to &quot;Copy Link Path&quot;">​</a></h3><p>Right-click any note tab or document list item to select <strong>Copy Link Path</strong>. This copies a workspace-relative reference link to your clipboard, making it easy to link documents together.</p><h2 id="link-hover-preview" tabindex="-1">Link Hover Preview <a class="header-anchor" href="#link-hover-preview" aria-label="Permalink to &quot;Link Hover Preview&quot;">​</a></h2><p>When viewing notes in <strong>Preview</strong> or <strong>Split</strong> modes, hovering over any note link displays a transient popup with two actions:</p><ul><li><strong>Copy</strong>: Copy the link target path to your clipboard.</li><li><strong>Navigate</strong>: Open and jump to the linked note.</li></ul><p>To prevent accidental navigation jumps, clicking a link directly in the preview pane is disabled.</p><h2 id="validation-indicators" tabindex="-1">Validation Indicators <a class="header-anchor" href="#validation-indicators" aria-label="Permalink to &quot;Validation Indicators&quot;">​</a></h2><p>Notely checks your Markdown as you write:</p><ul><li><strong>Markdown validation</strong> — flags structural issues (unclosed tables, bad heading levels, etc.)</li><li><strong>Typo checking</strong> — underlines suspected spelling errors in prose (skips code blocks). Right-click any flagged word to ignore it or add it to your custom spelling dictionary.</li><li><strong>Custom spelling dictionary</strong> — manage custom spelling dictionary words via the settings menu or the command palette (under &quot;Manage Spelling Dictionary&quot;).</li></ul><p>When issues are found, a badge appears in the editor header. Click it to jump to the first problem.</p><p>→ <a href="/settings-reference.html#typo-check">Typo and Validation Settings</a></p><h3 id="tab-context-menu" tabindex="-1">Tab Context Menu <a class="header-anchor" href="#tab-context-menu" aria-label="Permalink to &quot;Tab Context Menu&quot;">​</a></h3><p>Right-click any note tab at the top of the editor pane to access tab actions:</p><ul><li><strong>Close Actions</strong>: Close Tab, Close Other Tabs, Close Tabs to the Right, Close Saved Tabs, Close All Tabs.</li><li><strong>Reload from Disk</strong>: Force-reload the selected note from disk, discarding unsaved memory buffers.</li><li><strong>System Actions</strong>: Open in VS Code, Reveal in File Explorer.</li><li><strong>Personalization &amp; Linking</strong>: Set Icon &amp; Color, Copy Link Path.</li></ul><h3 id="external-disk-change-detection" tabindex="-1">External Disk Change Detection <a class="header-anchor" href="#external-disk-change-detection" aria-label="Permalink to &quot;External Disk Change Detection&quot;">​</a></h3><p>If an open note is modified externally on disk by another tool, Notely automatically:</p><ol><li>Detects the external file change.</li><li>Temporarily disables autosave to prevent overwriting external updates.</li><li>Displays a warning banner with a <strong>Reload content from disk</strong> button.</li></ol><p>Click <strong>Reload content from disk</strong>, press <code>Ctrl + Shift + R</code>, or right-click the tab and choose <strong>Reload from Disk</strong> to load the updated content.</p><h2 id="keyboard-shortcuts" tabindex="-1">Keyboard Shortcuts <a class="header-anchor" href="#keyboard-shortcuts" aria-label="Permalink to &quot;Keyboard Shortcuts&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>Shortcut</th></tr></thead><tbody><tr><td>New Note</td><td><code>Ctrl + N</code></td></tr><tr><td>Reload Current Note from Disk</td><td><code>Ctrl + Shift + R</code></td></tr><tr><td>Reload Workspace from Disk</td><td><code>Ctrl + Alt + R</code></td></tr><tr><td>Find in note</td><td><code>Ctrl + F</code></td></tr><tr><td>Find and Replace</td><td><code>Ctrl + H</code></td></tr><tr><td>Show Outline</td><td><code>Ctrl + Alt + L</code></td></tr><tr><td>Focus Mode</td><td><code>Ctrl + Alt + F</code></td></tr><tr><td>Version History</td><td><code>Ctrl + Shift + H</code></td></tr><tr><td>Screen Capture</td><td><code>Ctrl + Shift + S</code></td></tr><tr><td>Switch to Next Tab</td><td><code>Ctrl + Tab</code></td></tr><tr><td>Switch to Previous Tab</td><td><code>Ctrl + Shift + Tab</code></td></tr></tbody></table><p>→ <a href="/keyboard-shortcuts.html">Full Keyboard Shortcuts</a></p>',38)])])}const b=e(i,[["render",d]]);export{u as __pageData,b as default};
